SELECT interaction_type 
FROM image_interactions
WHERE interaction_id = 1;

SELECT title, ship_name, number_of_pages
FROM logbooks
WHERE number_of_pages = (SELECT MAX(number_of_pages) FROM logbooks);

SELECT COUNT(interaction_id) AS total_interactions
FROM image_interactions
WHERE image_id = 1;

SELECT title, ship_name, voyage_dates, number_of_pages
FROM logbooks
ORDER BY voyage_dates DESC;

SELECT title, ship_name, logbook_conditions, transcribed
FROM logbooks
WHERE logbook_conditions = 'Fair condition' AND transcribed = 0;

SELECT number_of_pages
FROM logbooks
WHERE logbook_id = 0;

SELECT COUNT(logbook_id) AS total_transcribed_logbooks
FROM logbooks
WHERE transcribed = 1;

SELECT COUNT(*) AS classification_count
FROM zooniverse_data
WHERE classification_date = '2022-01-02';

SELECT set_key
FROM set_keys
WHERE set_key_id = 0;

SELECT transcription_status, COUNT(*) AS number_of_pages
FROM logbook_pages
GROUP BY transcription_status;

SELECT set_key
FROM set_keys
WHERE set_key = 'william_baylies_2';

SELECT COUNT(*) 
FROM transcriptions 
WHERE user_id = (SELECT user_id FROM users WHERE username = 'john_doe');

SELECT COUNT(image_quality) AS high_quality_images_count
FROM page_images
WHERE image_quality = 'high';

SELECT user_id, COUNT(transcription_id) AS total_transcriptions
FROM transcriptions
GROUP BY user_id;

SELECT COUNT(page_id) AS count_good_condition_pages
FROM logbook_pages
WHERE page_conditions = 'Good condition';

SELECT classification_date, classification_details, COUNT(classification_id) AS total_classifications
FROM zooniverse_data
GROUP BY classification_date, classification_details;

SELECT classification_id, classification_date, classification_details
FROM zooniverse_data
WHERE classification_date = '2022-01-01';

SELECT username
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM image_interactions
);

SELECT title, number_of_pages 
FROM logbooks
ORDER BY number_of_pages DESC;
